#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        int x1,y1,x2,y2; scanf("%d %d", &x1, &y1); scanf("%d %d", &x2, &y2);
        int p1 = (x1 + y1) & 1;
        int p2 = (x2 + y2) & 1;
        int third = 3; // distinct from 1 and 2
        for(int i=1;i<=N;i++){
            for(int j=1;j<=M;j++){
                int val;
                if(p1!=p2){
                    val = ((i+j)&1)==p1 ? 1 : 2;
                }else{
                    if(i==x1 && j==y1) val = 1;
                    else if(i==x2 && j==y2) val = 2;
                    else if(((i+j)&1)==p1) val = 1; // reuse color 1
                    else val = third;
                }
                printf("%d", val);
                if(j<M) printf(" ");
            }
            printf("\n");
        }
    }
    return 0;
}

