import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            int x1 = fs.nextInt();
            int y1 = fs.nextInt();
            int x2 = fs.nextInt();
            int y2 = fs.nextInt();
            int p1 = (x1 + y1) & 1;
            int p2 = (x2 + y2) & 1;
            int third = 3;
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= M; j++) {
                    int val;
                    if (p1 != p2) {
                        val = ((i + j) & 1) == p1 ? 1 : 2;
                    } else {
                        if (i == x1 && j == y1) val = 1;
                        else if (i == x2 && j == y2) val = 2;
                        else if (((i + j) & 1) == p1) val = 1;
                        else val = third;
                    }
                    out.append(val);
                    if (j == M) out.append('\n'); else out.append(' ');
                }
            }
        }
        System.out.print(out.toString());
    }
    // Fast scanner for competitive programming
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

