#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        x1 = int(next(it)); y1 = int(next(it))
        x2 = int(next(it)); y2 = int(next(it))
        p1 = (x1 + y1) & 1
        p2 = (x2 + y2) & 1
        third = 3
        for i in range(1, N+1):
            row = []
            for j in range(1, M+1):
                if p1 != p2:
                    val = 1 if ((i + j) & 1) == p1 else 2
                else:
                    if i == x1 and j == y1:
                        val = 1
                    elif i == x2 and j == y2:
                        val = 2
                    elif ((i + j) & 1) == p1:
                        val = 1
                    else:
                        val = third
                row.append(str(val))
            out_lines.append(' '.join(row))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

